95:                public Logger::Loggable<Logger::Id::config> {
96: public:
97:   Config(const envoy::extensions::filters::http::header_to_metadata::v3::Config config,
98:          Regex::Engine& regex_engine, bool per_route = false);
99: 
100:   const HeaderToMetadataRules& requestRules() const { return request_rules_; }
101:   const HeaderToMetadataRules& responseRules() const { return response_rules_; }
102:   bool doResponse() const { return response_set_; }
103:   bool doRequest() const { return request_set_; }
104: 
105: private:
106:   using ProtobufRepeatedRule = Protobuf::RepeatedPtrField<ProtoRule>;
107: 
108:   /**
109:    *  configToVector is a helper function for converting from configuration (protobuf types) into
110:    *  STL containers for usage elsewhere.
111:    *
112:    *  @param config A protobuf repeated field of metadata that specifies what headers to convert to
113:    *         metadata
114:    *  @param vector A vector that will be populated with the configuration data from config
115:    *  @return true if any configuration data was added to the vector, false otherwise. Can be used
116:    *          to validate whether the configuration was empty.
117:    */
118:   static bool configToVector(const ProtobufRepeatedRule&, HeaderToMetadataRules&, Regex::Engine&);
119: 
120:   const std::string& decideNamespace(const std::string& nspace) const;
121: 
122:   HeaderToMetadataRules request_rules_;
123:   HeaderToMetadataRules response_rules_;
124:   bool response_set_;
125:   bool request_set_;
