123: HeaderToMetadataFilter::HeaderToMetadataFilter(const ConfigSharedPtr config) : config_(config) {}
124: 
125: HeaderToMetadataFilter::~HeaderToMetadataFilter() = default;
126: 
127: Http::FilterHeadersStatus HeaderToMetadataFilter::decodeHeaders(Http::RequestHeaderMap& headers,
128:                                                                 bool) {
129:   const auto* config = getConfig();
130:   if (config->doRequest()) {
131:     writeHeaderToMetadata(headers, config->requestRules(), *decoder_callbacks_);
132:   }
133: 
134:   return Http::FilterHeadersStatus::Continue;
135: }
136: 
137: void HeaderToMetadataFilter::setDecoderFilterCallbacks(
138:     Http::StreamDecoderFilterCallbacks& callbacks) {
139:   decoder_callbacks_ = &callbacks;
140: }
141: 
142: Http::FilterHeadersStatus HeaderToMetadataFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
143:                                                                 bool) {
144:   const auto* config = getConfig();
145:   if (config->doResponse()) {
146:     writeHeaderToMetadata(headers, config->responseRules(), *encoder_callbacks_);
147:   }
148:   return Http::FilterHeadersStatus::Continue;
149: }
