    32→                                                                     bool) {
    33→  const auto* config = getConfig();
    34→  for (const auto& [key, value] : config->requestHeaders()) {
    35→    headers.addViaMove(Http::LowerCaseString(key), std::string(value));
    36→  }
    37→  return Http::FilterHeadersStatus::Continue;
    38→}
