#include <memory>

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"

#include "source/common/http/header_map_impl.h"
#include "source/common/protobuf/protobuf.h"
#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"
#include "test/mocks/stream_info/mocks.h"
#include "test/test_common/utility.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjectionFilter {
namespace {

class CustomHeaderInjectionTest : public testing::Test {
public:
  void initializeFilter(const std::string& yaml) {
    envoy::extensions::filters::http::custom_header_injection::v3::Config config;
    TestUtility::loadFromYaml(yaml, config);
    config_ = std::make_shared<Config>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  ConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
  NiceMock<Envoy::StreamInfo::MockStreamInfo> stream_info_;
};

/**
 * Test request header injection.
 */
TEST_F(CustomHeaderInjectionTest, RequestHeaderInjection) {
  const std::string config_yaml = R"EOF(
request_headers:
  - key: x-custom-header
    value: custom-value
)EOF";

  initializeFilter(config_yaml);

  Http::TestRequestHeaderMapImpl headers;
  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillOnce(testing::ReturnRef(stream_info_));

  auto status = filter_->decodeHeaders(headers, false);
  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
  EXPECT_THAT(headers.get(Http::LowerCaseString("x-custom-header")),
              testing::StrEq("custom-value"));
}

/**
 * Test response header injection.
 */
TEST_F(CustomHeaderInjectionTest, ResponseHeaderInjection) {
  const std::string config_yaml = R"EOF(
response_headers:
  - key: x-custom-response
    value: response-value
)EOF";

  initializeFilter(config_yaml);

  Http::TestResponseHeaderMapImpl headers;
  EXPECT_CALL(encoder_callbacks_, streamInfo()).WillOnce(testing::ReturnRef(stream_info_));

  auto status = filter_->encodeHeaders(headers, false);
  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
  EXPECT_THAT(headers.get(Http::LowerCaseString("x-custom-response")),
              testing::StrEq("response-value"));
}

/**
 * Test both request and response header injection.
 */
TEST_F(CustomHeaderInjectionTest, BothHeaderInjection) {
  const std::string config_yaml = R"EOF(
request_headers:
  - key: x-custom-request
    value: request-value
response_headers:
  - key: x-custom-response
    value: response-value
)EOF";

  initializeFilter(config_yaml);

  // Test request headers
  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillOnce(testing::ReturnRef(stream_info_));
  auto request_status = filter_->decodeHeaders(request_headers, false);
  EXPECT_EQ(request_status, Http::FilterHeadersStatus::Continue);
  EXPECT_THAT(request_headers.get(Http::LowerCaseString("x-custom-request")),
              testing::StrEq("request-value"));

  // Test response headers
  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_CALL(encoder_callbacks_, streamInfo()).WillOnce(testing::ReturnRef(stream_info_));
  auto response_status = filter_->encodeHeaders(response_headers, false);
  EXPECT_EQ(response_status, Http::FilterHeadersStatus::Continue);
  EXPECT_THAT(response_headers.get(Http::LowerCaseString("x-custom-response")),
              testing::StrEq("response-value"));
}

/**
 * Test multiple request headers.
 */
TEST_F(CustomHeaderInjectionTest, MultipleRequestHeaders) {
  const std::string config_yaml = R"EOF(
request_headers:
  - key: x-header-1
    value: value-1
  - key: x-header-2
    value: value-2
)EOF";

  initializeFilter(config_yaml);

  Http::TestRequestHeaderMapImpl headers;
  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillOnce(testing::ReturnRef(stream_info_));

  auto status = filter_->decodeHeaders(headers, false);
  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
  EXPECT_THAT(headers.get(Http::LowerCaseString("x-header-1")), testing::StrEq("value-1"));
  EXPECT_THAT(headers.get(Http::LowerCaseString("x-header-2")), testing::StrEq("value-2"));
}

} // namespace
} // namespace CustomHeaderInjectionFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

